INSERT INTO `project_workflow_templates` (`template_id`, `category`, `template_name`, `description`, `stages`, `created_at`, `updated_at`) VALUES
('tpl-brand', 'Brand', 'Brand Development Workflow', 'Brand creation and launch process', '[{\"name\": \"Concept Development\", \"division\": \"Marketing\", \"description\": \"Brand concept and strategy\"}, {\"name\": \"Visual Identity\", \"division\": \"Creative\", \"description\": \"Logo, colors, and brand assets\"}, {\"name\": \"Brand Guidelines\", \"division\": \"Creative\", \"description\": \"Create brand style guide\"}, {\"name\": \"Management Review\", \"division\": \"Management\", \"description\": \"Executive approval\"}, {\"name\": \"Launch Campaign\", \"division\": \"Marketing\", \"description\": \"Brand launch and promotion\"}]', '2026-05-10 21:57:26', '2026-05-10 21:57:26'),
('tpl-event', 'Event', 'Event Management Workflow', 'Complete event planning and execution', '[{\"name\": \"Event Planning\", \"division\": \"Event Team\", \"description\": \"Define event scope and objectives\"}, {\"name\": \"Venue & Logistics\", \"division\": \"Operations\", \"description\": \"Book venue and arrange logistics\"}, {\"name\": \"Marketing & Promotion\", \"division\": \"Marketing\", \"description\": \"Promote event and manage registrations\"}, {\"name\": \"Content Preparation\", \"division\": \"Creative\", \"description\": \"Prepare presentations and materials\"}, {\"name\": \"Event Execution\", \"division\": \"Event Team\", \"description\": \"Run the event\"}, {\"name\": \"Post-Event Analysis\", \"division\": \"Event Team\", \"description\": \"Gather feedback and report\"}]', '2026-05-10 21:57:26', '2026-05-10 21:57:26'),
('tpl-factory', 'Factory', 'Factory Operations Workflow', 'Factory production and delivery process', '[{\"name\": \"Order Received\", \"division\": \"Sales\", \"description\": \"Process customer order\"}, {\"name\": \"Material Preparation\", \"division\": \"Warehouse\", \"description\": \"Prepare raw materials\"}, {\"name\": \"Production Planning\", \"division\": \"Production\", \"description\": \"Schedule production\"}, {\"name\": \"Manufacturing\", \"division\": \"Factory\", \"description\": \"Produce items\"}, {\"name\": \"Quality Inspection\", \"division\": \"QC\", \"description\": \"Inspect finished products\"}, {\"name\": \"Packaging & Labeling\", \"division\": \"Warehouse\", \"description\": \"Package for delivery\"}, {\"name\": \"Delivery\", \"division\": \"Logistics\", \"description\": \"Ship to customer\"}]', '2026-05-10 21:57:26', '2026-05-10 21:57:26'),
('tpl-lainnya', 'Lainnya', 'General Project Workflow', 'Generic workflow for other project types', '[{\"name\": \"Planning\", \"division\": \"Project Team\", \"description\": \"Project planning phase\"}, {\"name\": \"Execution\", \"division\": \"Project Team\", \"description\": \"Execute project\"}, {\"name\": \"Review\", \"division\": \"Management\", \"description\": \"Review and approve\"}, {\"name\": \"Completion\", \"division\": \"Project Team\", \"description\": \"Finalize and close\"}]', '2026-05-10 21:57:26', '2026-05-10 21:57:26'),
('tpl-manufacture', 'Manufacture', 'Manufacturing Workflow', 'Complete manufacturing process from planning to distribution', '[{\"name\": \"Planning & Design\", \"division\": \"Marketing\", \"description\": \"Product planning and initial design\"}, {\"name\": \"Creative Design\", \"division\": \"Creative\", \"description\": \"Detailed design and mockups\"}, {\"name\": \"Material Sourcing\", \"division\": \"Procurement\", \"description\": \"Source and order materials\"}, {\"name\": \"Production\", \"division\": \"Factory\", \"description\": \"Manufacturing process\"}, {\"name\": \"Quality Control\", \"division\": \"QC\", \"description\": \"Quality inspection and testing\"}, {\"name\": \"Packaging\", \"division\": \"Factory\", \"description\": \"Product packaging\"}, {\"name\": \"Distribution\", \"division\": \"Logistics\", \"description\": \"Shipping and delivery\"}]', '2026-05-10 21:57:26', '2026-05-10 21:57:26'),
('tpl-office', 'Office', 'Office Project Workflow', 'Standard office project management', '[{\"name\": \"Initiation\", \"division\": \"Management\", \"description\": \"Project approval and kickoff\"}, {\"name\": \"Planning\", \"division\": \"Project Team\", \"description\": \"Detailed project planning\"}, {\"name\": \"Execution\", \"division\": \"Project Team\", \"description\": \"Execute project tasks\"}, {\"name\": \"Monitoring\", \"division\": \"Project Team\", \"description\": \"Track progress and adjust\"}, {\"name\": \"Review & Closure\", \"division\": \"Management\", \"description\": \"Final review and documentation\"}]', '2026-05-10 21:57:26', '2026-05-10 21:57:26');
INSERT INTO `projects` (`id`, `project_id`, `project_name`, `category`, `owner`, `assignees`, `status`, `description`, `notes`, `url`, `accounts`, `brief`, `asset_bundle`, `progress`, `due_date`, `start_date`, `closed_date`, `version`, `created_at`, `updated_at`, `created_by`, `visibility`, `workspace_id`, `org_unit_id`) VALUES
(12, 'PRJ-001', 'social media automation', 'Internal', 'taufiknurrahmanridwan', 'taufiknurrahmanridwan, imancanggawigunaskom, rizkiputraramadhan, muhammadtaufanakbar', 'Active', 'Proyek ini bertujuan mengotomatisasi posting di media sosial untuk meningkatkan keterlibatan. Menggunakan API dan skrip terjadwal.', 'Proyek ini bertujuan mengotomatisasi posting di media sosial untuk meningkatkan keterlibatan. Menggunakan API dan skrip terjadwal.', NULL, NULL, 'Tujuan proyek adalah mengotomatisasi posting konten harian, mengoptimalkan jadwal, dan memantau metrik. Hasilnya termasuk peningkatan follower, engagement, dan efisiensi waktu.', 'Notes\nProyek ini bertujuan mengotomatisasi posting di media sosial untuk meningkatkan keterlibatan. Menggunakan API dan skrip terjadwal.\n\nBrief\nTujuan proyek adalah mengotomatisasi posting konten harian, mengoptimalkan jadwal, dan memantau metrik. Hasilnya termasuk peningkatan follower, engagement, dan efisiensi waktu.', '0.00', NULL, '2026-06-22 15:23:41', NULL, 1, '2026-06-22 15:23:41', '2026-06-26 01:49:25', 2, 'public', 'WS-009', NULL),
(13, 'PRJ-002', 'ai kindness + coach chat ai - poin internal karyawan', 'Pertamina', 'imancanggawigunaskom', 'imancanggawigunaskom, rizkiputraramadhan', 'Active', 'Proyek ini bertujuan mengembangkan sistem chat AI yang menekankan sikap kebaikan (AI kindness) dan fungsi pelatihan (coach chat AI) untuk meningkatkan kepuasan dan produktivitas karyawan. Blocker utama adalah integrasi data internal yang aman dan memastikan AI dapat menyesuaikan respons dengan nilai perusahaan. Detail penting: perlu mekanisme penilaian poin internal karyawan berdasarkan interaksi AI serta pelaporan transparan ke manajemen.', 'Proyek ini bertujuan mengembangkan sistem chat AI yang menekankan sikap kebaikan (AI kindness) dan fungsi pelatihan (coach chat AI) untuk meningkatkan kepuasan dan produktivitas karyawan. Blocker utama adalah integrasi data internal yang aman dan memastikan AI dapat menyesuaikan respons dengan nilai perusahaan. Detail penting: perlu mekanisme penilaian poin internal karyawan berdasarkan interaksi AI serta pelaporan transparan ke manajemen.', NULL, NULL, 'Proyek ini bertujuan mengembangkan sistem chat AI yang menekankan sikap kebaikan (AI kindness) dan fungsi pelatihan (coach chat AI) untuk meningkatkan kepuasan dan produktivitas karyawan. Blocker utama adalah integrasi data internal yang aman dan memastikan AI dapat menyesuaikan respons dengan nilai perusahaan. Detail penting: perlu mekanisme penilaian poin internal karyawan berdasarkan interaksi AI serta pelaporan transparan ke manajemen.', 'Notes\nProyek ini bertujuan mengembangkan sistem chat AI yang menekankan sikap kebaikan (AI kindness) dan fungsi pelatihan (coach chat AI) untuk meningkatkan kepuasan dan produktivitas karyawan. Blocker utama adalah integrasi data internal yang aman dan memastikan AI dapat menyesuaikan respons dengan nilai perusahaan. Detail penting: perlu mekanisme penilaian poin internal karyawan berdasarkan interaksi AI serta pelaporan transparan ke manajemen.\n\nBrief\nProyek ini bertujuan mengembangkan sistem chat AI yang menekankan sikap kebaikan (AI kindness) dan fungsi pelatihan (coach chat AI) untuk meningkatkan kepuasan dan produktivitas karyawan. Blocker utama adalah integrasi data internal yang aman dan memastikan AI dapat menyesuaikan respons dengan nilai perusahaan. Detail penting: perlu mekanisme penilaian poin internal karyawan berdasarkan interaksi AI serta pelaporan transparan ke manajemen.', '0.00', NULL, '2026-06-22 15:25:33', NULL, 3, '2026-06-22 15:24:44', '2026-06-26 01:49:25', 2, 'public', 'WS-009', NULL),
(14, 'PRJ-003', 'ai digital intelligence (sentiment analysis)', 'Pertamina', 'muhammadtaufanakbar', 'muhammadtaufanakbar, taufiknurrahmanridwan', 'Active', 'Tugas ini berfokus pada penerapan analisis sentimen menggunakan AI untuk mengidentifikasi opini pelanggan dari data teks. Salah satu hambatan utama adalah keterbatasan dataset berlabel yang representatif, sehingga model perlu dilatih dengan data sintetis atau transfer learning. Penting juga untuk memastikan akurasi klasifikasi tidak terpengaruh oleh bias bahasa dan konteks budaya lokal.', 'Tugas ini berfokus pada penerapan analisis sentimen menggunakan AI untuk mengidentifikasi opini pelanggan dari data teks. Salah satu hambatan utama adalah keterbatasan dataset berlabel yang representatif, sehingga model perlu dilatih dengan data sintetis atau transfer learning. Penting juga untuk memastikan akurasi klasifikasi tidak terpengaruh oleh bias bahasa dan konteks budaya lokal.', NULL, NULL, '**Tujuan Utama**  \nMengembangkan sistem analisis sentimen berbasis AI untuk menilai persepsi pelanggan terhadap merek secara real‑time.\n\n**Persyaratan Utama**  \n1. Model NLP multibahasa (Indonesia & Inggris) dengan akurasi ≥ 85 % pada dataset percakapan media sosial.  \n2. Integrasi API streaming (Twitter, Facebook, Instagram) dan dashboard visualisasi KPI sentimen.  \n3. Keamanan data GDPR/PDPA dan kemampuan rollback model bila terjadi bias.\n\n**Hasil yang Diharapkan**  \nMeningkatkan pemahaman pelanggan dan respons pemasaran dengan laporan sentimen harian yang akurat, mempercepat pengambilan keputusan strategis.', 'Notes\nTugas ini berfokus pada penerapan analisis sentimen menggunakan AI untuk mengidentifikasi opini pelanggan dari data teks. Salah satu hambatan utama adalah keterbatasan dataset berlabel yang representatif, sehingga model perlu dilatih dengan data sintetis atau transfer learning. Penting juga untuk memastikan akurasi klasifikasi tidak terpengaruh oleh bias bahasa dan konteks budaya lokal.\n\nBrief\n**Tujuan Utama**  \nMengembangkan sistem analisis sentimen berbasis AI untuk menilai persepsi pelanggan terhadap merek secara real‑time.\n\n**Persyaratan Utama**  \n1. Model NLP multibahasa (Indonesia & Inggris) dengan akurasi ≥ 85 % pada dataset percakapan media sosial.  \n2. Integrasi API streaming (Twitter, Facebook, Instagram) dan dashboard visualisasi KPI sentimen.  \n3. Keamanan data GDPR/PDPA dan kemampuan rollback model bila terjadi bias.\n\n**Hasil yang Diharapkan**  \nMeningkatkan pemahaman pelanggan dan respons pemasaran dengan laporan sentimen harian yang akurat, mempercepat pengambilan keputusan strategis.', '0.00', NULL, '2026-06-22 15:26:40', NULL, 1, '2026-06-22 15:26:40', '2026-06-26 01:49:25', 2, 'public', 'WS-009', NULL),
(15, 'PRJ-004', 'ai workshop system', 'Pertamina', 'imancanggawigunaskom', 'imancanggawigunaskom, muhammadtaufanakbar', 'Active', 'Sistem workshop AI dirancang untuk menyediakan platform interaktif bagi peserta belajar dan mengimplementasikan model AI. Hambatan utama saat ini adalah keterbatasan data pelatihan serta integrasi API pihak ketiga yang belum stabil. Detail penting: perlu dukungan GPU, kebijakan keamanan data, dan modul evaluasi otomatis.', 'Sistem workshop AI dirancang untuk menyediakan platform interaktif bagi peserta belajar dan mengimplementasikan model AI. Hambatan utama saat ini adalah keterbatasan data pelatihan serta integrasi API pihak ketiga yang belum stabil. Detail penting: perlu dukungan GPU, kebijakan keamanan data, dan modul evaluasi otomatis.', NULL, NULL, '**Tujuan Utama**  \nMembangun sistem workshop AI yang memudahkan pengguna mengembangkan, menguji, dan menerapkan model AI secara kolaboratif.\n\n**Persyaratan Kunci**  \n- Antarmuka berbasis web responsif dengan integrasi Jupyter Notebook dan Docker untuk lingkungan eksperimental.  \n- Sistem manajemen versi dan pelacakan eksperimen (MLflow atau Weights & Biases) yang terintegrasi.  \n- Fitur kolaborasi real‑time, termasuk chat, komentar kode, dan review pull request.\n\n**Harapan Hasil**  \nPengguna dapat dengan cepat membangun, menguji, dan menyebarkan model AI, meningkatkan produktivitas tim dan kualitas produk akhir.', 'Notes\nSistem workshop AI dirancang untuk menyediakan platform interaktif bagi peserta belajar dan mengimplementasikan model AI. Hambatan utama saat ini adalah keterbatasan data pelatihan serta integrasi API pihak ketiga yang belum stabil. Detail penting: perlu dukungan GPU, kebijakan keamanan data, dan modul evaluasi otomatis.\n\nBrief\n**Tujuan Utama**  \nMembangun sistem workshop AI yang memudahkan pengguna mengembangkan, menguji, dan menerapkan model AI secara kolaboratif.\n\n**Persyaratan Kunci**  \n- Antarmuka berbasis web responsif dengan integrasi Jupyter Notebook dan Docker untuk lingkungan eksperimental.  \n- Sistem manajemen versi dan pelacakan eksperimen (MLflow atau Weights & Biases) yang terintegrasi.  \n- Fitur kolaborasi real‑time, termasuk chat, komentar kode, dan review pull request.\n\n**Harapan Hasil**  \nPengguna dapat dengan cepat membangun, menguji, dan menyebarkan model AI, meningkatkan produktivitas tim dan kualitas produk akhir.', '0.00', NULL, '2026-06-22 15:28:00', NULL, 1, '2026-06-22 15:28:00', '2026-06-26 01:49:25', 2, 'public', 'WS-009', NULL),
(16, 'PRJ-005', 'ai workshop system mentimeter', 'Pertamina', 'imancanggawigunaskom', 'imancanggawigunaskom, muhammadtaufanakbar', 'Planning', 'Workshop AI menggunakan Mentimeter bertujuan meningkatkan interaksi peserta dengan materi. Saat ini, keterbatasan koneksi internet di beberapa ruangan menjadi hambatan utama. Pastikan semua peserta memiliki akses Wi‑Fi yang stabil dan versi browser terbaru agar polling berjalan lancar.', 'Workshop AI menggunakan Mentimeter bertujuan meningkatkan interaksi peserta dengan materi. Saat ini, keterbatasan koneksi internet di beberapa ruangan menjadi hambatan utama. Pastikan semua peserta memiliki akses Wi‑Fi yang stabil dan versi browser terbaru agar polling berjalan lancar.', 'https://workshop-platform.raycorp.id/platform/events', 'fas\npa\na', '**Tujuan Utama**  \nMengembangkan sistem workshop AI berbasis Mentimeter untuk meningkatkan interaksi peserta dan evaluasi real‑time.\n\n**Persyaratan Utama**  \n- Integrasi API Mentimeter guna memfasilitasi polling dan kuis interaktif.  \n- Dashboard analitik real‑time yang menampilkan hasil polling dan feedback peserta.  \n- Sistem autentikasi aman serta dukungan multi‑bahasa.\n\n**Hasil yang Diharapkan**  \nPeserta workshop dapat berpartisipasi secara aktif melalui polling interaktif, sementara penyelenggara memperoleh data evaluasi real‑time yang memudahkan penyesuaian materi.', 'Notes\nWorkshop AI menggunakan Mentimeter bertujuan meningkatkan interaksi peserta dengan materi. Saat ini, keterbatasan koneksi internet di beberapa ruangan menjadi hambatan utama. Pastikan semua peserta memiliki akses Wi‑Fi yang stabil dan versi browser terbaru agar polling berjalan lancar.\n\nURLs\nhttps://workshop-platform.raycorp.id/platform/events\n\nAccounts\nfas\npa\na\n\nBrief\n**Tujuan Utama**  \nMengembangkan sistem workshop AI berbasis Mentimeter untuk meningkatkan interaksi peserta dan evaluasi real‑time.\n\n**Persyaratan Utama**  \n- Integrasi API Mentimeter guna memfasilitasi polling dan kuis interaktif.  \n- Dashboard analitik real‑time yang menampilkan hasil polling dan feedback peserta.  \n- Sistem autentikasi aman serta dukungan multi‑bahasa.\n\n**Hasil yang Diharapkan**  \nPeserta workshop dapat berpartisipasi secara aktif melalui polling interaktif, sementara penyelenggara memperoleh data evaluasi real‑time yang memudahkan penyesuaian materi.', '0.00', NULL, NULL, NULL, 1, '2026-06-23 08:48:45', '2026-06-26 01:49:25', 2, 'public', 'WS-009', NULL),
(17, 'PRJ-006', 'ai employee', 'Development', 'taufiknurrahmanridwan', 'taufiknurrahmanridwan', 'Planning', 'Proyek ini bertujuan mengembangkan karyawan virtual berbasis AI untuk meningkatkan efisiensi operasional perusahaan. Fokusnya pada integrasi chatbot, analitik data, dan pelatihan otomatis.', 'Proyek ini bertujuan mengembangkan karyawan virtual berbasis AI untuk meningkatkan efisiensi operasional perusahaan. Fokusnya pada integrasi chatbot, analitik data, dan pelatihan otomatis.', 'https://github.com/ai-employee/project\nhttps://docs.ai-employee.com', 'Admin | ai_admin | pass123 | Akses penuh\nDeveloper | dev_ai | devpass | Akses kode\nSupport | support_ai | suppass | Akses dukungan', 'Membangun karyawan AI yang dapat menangani tugas rutin, menjawab pertanyaan karyawan, dan menganalisis data kinerja. Hasilnya akan meningkatkan produktivitas, mengurangi beban kerja manusia, dan menyediakan wawasan berbasis data untuk pengambilan keputusan strategis. Proyek ini juga akan menyediakan modul pelatihan AI yang dapat disesuaikan untuk berbagai departemen.', 'Notes\nProyek ini bertujuan mengembangkan karyawan virtual berbasis AI untuk meningkatkan efisiensi operasional perusahaan. Fokusnya pada integrasi chatbot, analitik data, dan pelatihan otomatis.\n\nURLs\nhttps://github.com/ai-employee/project\nhttps://docs.ai-employee.com\n\nAccounts\nAdmin | ai_admin | pass123 | Akses penuh\nDeveloper | dev_ai | devpass | Akses kode\nSupport | support_ai | suppass | Akses dukungan\n\nBrief\nMembangun karyawan AI yang dapat menangani tugas rutin, menjawab pertanyaan karyawan, dan menganalisis data kinerja. Hasilnya akan meningkatkan produktivitas, mengurangi beban kerja manusia, dan menyediakan wawasan berbasis data untuk pengambilan keputusan strategis. Proyek ini juga akan menyediakan modul pelatihan AI yang dapat disesuaikan untuk berbagai departemen.', '0.00', NULL, NULL, NULL, 1, '2026-06-25 21:45:27', '2026-06-26 01:49:25', 2, 'public', 'WS-003', NULL);
