  CONSTRAINT `ai_messages_ibfk_2` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=32 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

DROP TABLE IF EXISTS `brain_config`;
CREATE TABLE `brain_config` (
  `id` int NOT NULL AUTO_INCREMENT,
  `config_type` enum('team','status','priority','progress','category') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
