  UNIQUE KEY `msg_id` (`msg_id`),
  KEY `idx_conv` (`conv_id`),
  KEY `idx_sender` (`sender`),
  KEY `idx_created` (`created_at` DESC),
  KEY `idx_deleted` (`is_deleted`),
  KEY `idx_session_id` (`session_id`),
  CONSTRAINT `chat_messages_ibfk_1` FOREIGN KEY (`conv_id`) REFERENCES `chat_conversations` (`conv_id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=84 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

DROP TABLE IF EXISTS `chat_sessions`;
CREATE TABLE `chat_sessions` (
  `session_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `conv_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `title` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'New Chat',
