  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `last_message_at` timestamp NULL DEFAULT NULL,
  `message_count` int DEFAULT '0',
  `folder` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'general',
  `is_archived` tinyint(1) DEFAULT '0',
  `is_pinned` tinyint(1) DEFAULT '0',
  PRIMARY KEY (`session_id`),
  KEY `idx_conv_id` (`conv_id`),
  KEY `idx_updated_at` (`updated_at` DESC),
  KEY `idx_folder` (`folder`),
  KEY `idx_archived` (`is_archived`),
  CONSTRAINT `chat_sessions_ibfk_1` FOREIGN KEY (`conv_id`) REFERENCES `chat_conversations` (`conv_id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

DROP TABLE IF EXISTS `logs`;
