  `created_by` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `unit_code` (`unit_code`),
  KEY `owner_username` (`owner_username`),
  KEY `direksi_username` (`direksi_username`),
  KEY `manager_username` (`manager_username`),
  KEY `created_by` (`created_by`),
  KEY `idx_parent` (`parent_id`),
  KEY `idx_path` (`path`),
  KEY `idx_type` (`unit_type`),
  KEY `idx_level` (`level`),
  KEY `idx_active` (`is_active`),
  KEY `idx_organizational_units_workspace_id` (`workspace_id`),
  CONSTRAINT `fk_organizational_units_workspace` FOREIGN KEY (`workspace_id`) REFERENCES `workspaces` (`workspace_id`) ON DELETE SET NULL,
