DROP TABLE IF EXISTS `users`;
CREATE TABLE `users` (
  `id` int NOT NULL AUTO_INCREMENT,
  `username` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `password` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `full_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `email` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `avatar` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `bio` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `phone` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `employee_id` varchar(100) DEFAULT NULL,
  `role` enum('admin','user') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'user',
  `job_position` varchar(255) DEFAULT NULL,
  `organization` varchar(255) DEFAULT NULL,
  `is_active` tinyint(1) DEFAULT '1',
  `hierarchy_level` enum('owner','direksi','manager','staff') DEFAULT 'staff',
  `direktur_level` enum('owner','direktur_office','direktur_manufacturing','manager','staff') DEFAULT 'staff',
  `division` varchar(100) DEFAULT NULL,
  `manager_username` varchar(50) DEFAULT NULL,
  `direksi_username` varchar(50) DEFAULT NULL,
  `org_unit_id` int DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `last_login` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `username` (`username`),
  KEY `idx_username` (`username`),
  KEY `idx_email` (`email`),
  KEY `idx_employee_id` (`employee_id`),
  KEY `idx_is_active` (`is_active`),
  KEY `fk_manager` (`manager_username`),
  KEY `fk_direksi` (`direksi_username`),
  KEY `fk_org_unit` (`org_unit_id`)
) ENGINE=InnoDB AUTO_INCREMENT=117 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

DROP VIEW IF EXISTS `v_org_hierarchy`;
select `ou`.`id` AS `id`,`ou`.`unit_code` AS `unit_code`,`ou`.`workspace_id` AS `workspace_id`,`ou`.`unit_name` AS `unit_name`,`ou`.`unit_type` AS `unit_type`,`ou`.`office_type` AS `office_type`,`ou`.`parent_id` AS `parent_id`,`ou`.`level` AS `level`,`ou`.`path` AS `path`,`ou`.`sort_order` AS `sort_order`,`ou`.`owner_username` AS `owner_username`,`ou`.`direksi_username` AS `direksi_username`,`ou`.`manager_username` AS `manager_username`,`ou`.`description` AS `description`,`ou`.`color` AS `color`,`ou`.`icon` AS `icon`,`ou`.`is_active` AS `is_active`,`ou`.`staff_count` AS `staff_count`,`ou`.`created_at` AS `created_at`,`ou`.`updated_at` AS `updated_at`,`ou`.`created_by` AS `created_by`,`owner`.`full_name` AS `owner_name`,`owner`.`avatar` AS `owner_avatar`,`dir`.`full_name` AS `direksi_name`,`dir`.`avatar` AS `direksi_avatar`,`mgr`.`full_name` AS `manager_name`,`mgr`.`avatar` AS `manager_avatar`,count(distinct `ous`.`username`) AS `assigned_staff`,count(distinct `u`.`username`) AS `member_count`,count(distinct `p`.`project_id`) AS `project_count`,count(distinct `t`.`task_id`) AS `task_count` from (((((((`raymaizing-task-db`.`organizational_units` `ou` left join `raymaizing-task-db`.`users` `owner` on((`owner`.`username` = `ou`.`owner_username`))) left join `raymaizing-task-db`.`users` `dir` on((`dir`.`username` = `ou`.`direksi_username`))) left join `raymaizing-task-db`.`users` `mgr` on((`mgr`.`username` = `ou`.`manager_username`))) left join `raymaizing-task-db`.`org_unit_staff` `ous` on((`ou`.`id` = `ous`.`org_unit_id`))) left join `raymaizing-task-db`.`users` `u` on(((`u`.`org_unit_id` = `ou`.`id`) and (`u`.`is_active` = 1)))) left join `raymaizing-task-db`.`projects` `p` on((`p`.`org_unit_id` = `ou`.`id`))) left join `raymaizing-task-db`.`tasks` `t` on((`t`.`org_unit_id` = `ou`.`id`))) group by `ou`.`id`;

DROP TABLE IF EXISTS `weekly_snapshot`;
CREATE TABLE `weekly_snapshot` (
  `id` int NOT NULL AUTO_INCREMENT,
  `timestamp` datetime DEFAULT CURRENT_TIMESTAMP,
  `item_type` enum('Project','Task') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `item_id` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `item_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `project_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `change_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `from_version` int DEFAULT NULL,
  `to_version` int DEFAULT NULL,
  `from_value` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `to_value` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `changed_by` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `notes` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  PRIMARY KEY (`id`),
  KEY `idx_item` (`item_type`,`item_id`),
  KEY `idx_timestamp` (`timestamp`)
) ENGINE=InnoDB AUTO_INCREMENT=65 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

DROP TABLE IF EXISTS `workspace_invites`;
